import { ChangeDetectionStrategy, Component, Injector, OnInit } from '@angular/core';
import { of } from 'rxjs';
import { DATA_DUMMY } from 'src/app/core';
import { BaseClassTemplate, LB } from 'src/app/core/class';
import { URLz } from 'src/app/core/enums/url.enum';

@Component({
  selector: 'aam-admin',
  templateUrl: './admin.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class AdminComponent extends BaseClassTemplate implements OnInit {
  ngOnInit() {
    console.log(this._activeRoute.snapshot.data)
    this.initTables();
  }
  initTables() {
    this.lb = new LB({
      isDummy: true,
      ep: URLz.$,
      query: this._fb.group({'is_advance': ['1']}).value,
    }, ['id','title','gender','email','status','desc','createdAt','updatedAt', 'actions']);
    this.lb.beforeHit = () => {
      let records: any = DATA_DUMMY('Admin');
      console.log(records)
      this.lb.ds.data = records
      this.lb.tbl.length = records.length;
      return of(this.lb);
    }
    this.lb.init();
    this.lb.refresh();
    this.lb.reset();
  }
}
