import { ChangeDetectionStrategy, Component, OnInit } from '@angular/core';
import { of } from 'rxjs';
import { DATA_DUMMY } from 'src/app/core';
import { BaseClassTemplate, LB } from 'src/app/core/class';
import { URLz } from 'src/app/core/enums';

@Component({
  selector: 'aam-student',
  templateUrl: './student.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush

})
export class StudentComponent extends BaseClassTemplate implements OnInit {
  ngOnInit() {
    console.log(this._activeRoute.snapshot.data)
    this.initTables();
  }
  initTables() {
    this.lb = new LB({
      isDummy: true,
      ep: URLz.$,
      query: this._fb.group({'is_advance': ['1']}).value,
    }, ['id','code','name','className','section','status','actions']);
    this.lb.beforeHit = () => {
      let records: any = DATA_DUMMY('Student');
      console.log(records)
      this.lb.ds.data = records
      this.lb.tbl.length = records.length;
      return of(this.lb);
    }
    this.lb.init();
    this.lb.refresh();
    this.lb.reset();
  }
}
