import { Component, OnInit } from '@angular/core';
import { ActivatedRoute } from '@angular/router';
import { BaseClassTemplate } from 'src/app/core/class';
import { URLz } from 'src/app/core/enums/url.enum';

@Component({
  selector: 'aam-user-type-add',
  templateUrl: './user-type-add.component.html',
  styleUrls: ['./user-type-add.component.scss']
})
export class UserTypeAddComponent extends BaseClassTemplate implements OnInit {
  constructor(private route: ActivatedRoute) {
    super();
    this.param.ep = URLz.NO_SET
  }

  ngOnInit(): void {
    this._id = this.getQuery('id');
    this.initform();
    if (this._id != "null" && Number(this._id) > 0) {
      this.onEdit();
    } else {
      this._fs._form.removeControl("id");
    }
  }
  initform(d: any = {}) {
    this._fs._form = this._fb.group({
      id: [d?.id || ''],
      title: [d?.title || '', this._vs._val('Name', {minChar: 4, alpha: 1 })],
      desc: [d?.title || '', this._vs._val('', { maxChar: 255, specialChar: 1 })],
    });
  }
  onEdit() {
    this._http
      .get({ ...this.param, resource: this._id })
      .subscribe((res: any) => {
        let data = res.data.row;
        this.initform(data);
      });
  }

}
